#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <unistd.h.h>
#include <string.h>

#define MAX_THREADS 10
#define TIME_QUANTUM 2

// Thread control block
typedef struct ThreadControlBlock {
 int tid; // Thread ID
 int arrival_time; // When thread arrives in ready queue
 int burst_time; // Total CPU burst needed
 int remaining_time; // Remaining execution time
 int priority; // Thread priority (lower = higher priority)
 int waiting_time; // Time spent waiting in ready queue
 int turnaround_time; // Completion time - arrival time
 int started; // Whether thread has started execution
 pthread_t thread; // POSIX thread handle
 int *counter; // Shared counter for simulation
 pthread_mutex_t *lock; // Shared mutex for synchronization
} TCB;

// Ready queue structure
typedef struct ReadyQueue {
 TCB *threads[MAX_THREADS];
 int front;
 int rear;
 int size;
} ReadyQueue;

// Initialize ready queue
void initQueue(ReadyQueue *queue) {
 queue->front = 0;
 queue->rear = -1;
 queue->size = 0;
}

// Check if queue is empty
int isEmpty(ReadyQueue *queue) {
 return queue->size == 0;
}

// Check if queue is full
int isFull(ReadyQueue *queue) {
 return queue->size >= MAX_THREADS;
}

// Enqueue thread to ready queue
void enqueue(ReadyQueue *queue, TCB *thread) {
 if (isFull(queue)) {
 printf("Queue is full!\n");
 return;
 }
 queue->rear = (queue->rear + 1) % MAX_THREADS;
 queue->threads[queue->rear] = thread;
 queue->size++;
}

// Dequeue thread from ready queue
TCB* dequeue(ReadyQueue *queue) {
 if (isEmpty(queue)) {
 return NULL;
 }
 TCB *thread = queue->threads[queue->front];
 queue->front = (queue->front + 1) % MAX_THREADS;
 queue->size--;
 return thread;
}

// Round-Robin scheduler simulation
void* threadWorker(void *arg) {
 TCB *tcb = (TCB *)arg;

 // Simulate thread execution
 printf("Thread T%d: Starting execution (Priority: %d)\n", 
 tcb->tid, tcb->priority);

 // Simulate CPU burst
 for (int i = 0; i < tcb->burst_time; i++) {
 sleep(1); // Simulate 1 unit of work

 pthread_mutex_lock(tcb->lock);
 (*tcb->counter)++;
 tcb->remaining_time--;

 printf("Thread T%d: Executed, Remaining: %d, Counter: %d\n",
 tcb->tid, tcb->remaining_time, *tcb->counter);

 pthread_mutex_unlock(tcb->lock);
 }

 printf("Thread T%d: Completed! Waiting: %d, Turnaround: %d\n",
 tcb->tid, tcb->waiting_time, tcb->turnaround_time);

 return NULL;
}

// Scheduler: selects next thread from queue (Priority-based)
TCB* priorityScheduler(ReadyQueue *readyQueue) {
 if (isEmpty(readyQueue)) return NULL;

 int max_priority = 999;
 int best_index = -1;
 int original_size = readyQueue->size;

 // Find highest priority thread
 for (int i = 0; i < original_size; i++) {
 TCB *t = dequeue(readyQueue);
 if (t->priority < max_priority) {
 max_priority = t->priority;
 best_index = i;
 }
 enqueue(readyQueue, t);
 }

 // Dequeue the highest priority thread
 for (int i = 0; i < original_size; i++) {
 TCB *t = dequeue(readyQueue);
 if (i == best_index) {
 return t;
 }
 enqueue(readyQueue, t);
 }

 return NULL;
}

// Simulate context switching
void contextSwitch(TCB *from, TCB *to) {
 printf("\n>>> Context Switch: T%d -> T%d <<<\n", 
 from ? from->tid : 0, to->tid);
 printf(" Dispatch latency: saving context, switching to user mode\n");
}

// Round-Robin scheduling demo
void runRoundRobin(TCB threads[], int n) {
 printf("\n=== ROUND-ROBIN SCHEDULING (Quantum: %d) ===\n", TIME_QUANTUM);

 ReadyQueue queue;
 initQueue(&queue);

 int current_time = 0;
 int completed = 0;
 int counter = 0;
 pthread_mutex_t lock;
 pthread_mutex_init(&lock, NULL);

 // Add initial threads to queue
 for (int i = 0; i < n; i++) {
 threads[i].remaining_time = threads[i].burst_time;
 threads[i].counter = &counter;
 threads[i].lock = &lock;
 enqueue(&queue, &threads[i]);
 }

 TCB *current = NULL;

 while (completed < n) {
 if (isEmpty(&queue)) {
 printf("Ready queue empty, CPU idle\n");
 break;
 }

 // Get next thread from queue
 if (current && current->remaining_time > 0) {
 enqueue(&queue, current); // Re-add if not finished
 }

 current = dequeue(&queue);

 // Execute for time quantum or remaining time
 int exec_time = (current->remaining_time > TIME_QUANTUM) ? 
 TIME_QUANTUM : current->remaining_time;

 printf("\n[Time %d] Executing Thread T%d for %d units\n",
 current_time, current->tid, exec_time);

 // Simulate execution
 for (int i = 0; i < exec_time; i++) {
 sleep(1);
 current_time++;
 current->remaining_time--;
 counter++;

 // Update waiting time for other threads in queue
 for (int j = 0; j < queue.size; j++) {
 queue.threads[j]->waiting_time++;
 }
 }

 printf("Thread T%d: remaining=%d, waited=%d\n",
 current->tid, current->remaining_time, current->waiting_time);

 if (current->remaining_time == 0) {
 completed++;
 current->turnaround_time = current_time - current->arrival_time;
 printf("*** Thread T%d COMPLETED (WT: %d, TAT: %d) ***\n",
 current->tid, current->waiting_time, current->turnaround_time);
 }
 }

 printf("\n--- Summary ---\n");
 int total_wait = 0, total_turnaround = 0;
 for (int i = 0; i < n; i++) {
 printf("T%d: Waiting=%d, Turnaround=%d\n",
 threads[i].tid, threads[i].waiting_time, threads[i].turnaround_time);
 total_wait += threads[i].waiting_time;
 total_turnaround += threads[i].turnaround_time;
 }
 printf("Average Waiting Time: %.2f\n", (float)total_wait/n);
 printf("Average Turnaround Time: %.2f\n", (float)total_turnaround/n);

 pthread_mutex_destroy(&lock);
}

int main() {
 // Create test threads: {tid, arrival, burst, priority}
 TCB threads[4] = {
 {1, 0, 10, 0, 0, 0, 0},
 {2, 1, 5, 0, 0, 0, 0},
 {3, 2, 8, 0, 0, 0, 0},
 {4, 3, 6, 0, 0, 0, 0}
 };

 printf("Thread Scheduling Simulation\n");
 printf("===========================\n");
 printf("Threads: T1(burst=10), T2(burst=5), T3(burst=8), T4(burst=6)\n");

 // Run Round-Robin scheduling
 runRoundRobin(threads, 4);

 return 0;
}
